window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2019>1","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"BASIC CONCEPTS : MEANING AND DIFFERENCES BETWEEN SUBSISTENCE AND COMMERCIAL AGRICULTURE","question":"Which of the following statements best describes commercial farming?","images":[],"options":{"A":"Production of plants and animals for family consumption","B":"Large scale agricultural production for sale","C":"Large scale agricultural production for family consumption","D":"Use of family labour for large scale agricultural production"},"answer":"B","explanation":"Commercial farming is best described as large scale agricultural production for sale. This is because the main aim of commercial farming is to produce crops or livestock on a large scale for sale and make profit. The other options do not accurately describe commercial farming as they either involve production for family consumption or use of family labour, which are characteristics of subsistence farming, not commercial farming.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>2","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which of the following problems are associated with agricultural marketing in West Africa?  I. Seasonality of produce  II. Transportation of produce  III. Access to credit","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"The problems associated with marketing agricultural produce in West Africa include  - Transport of Produce  - Seasonality of produce  - Access to credit.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>3","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"An advantage of communal land tenure system is that it","images":[],"options":{"A":"encourages use of land for permanent projects by individuals.","B":"makes land cheap to acquire.","C":"leads to fragmentation.","D":"does not promote farm mechanization."},"answer":"B","explanation":"Communal land tenure system is a traditional system of land ownership where land is owned in common by a community. This system makes land cheap to acquire because it is not owned by individuals but by the community. Therefore, individuals do not have to pay high prices to acquire land.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>4","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Which of the following implements is used for primary tillage?","images":[],"options":{"A":"Ridger","B":"Cultivator","C":"Plough","D":"Harrow"},"answer":"C","explanation":"Ploughs are used for primary tillage.  It should be noted that ploughs are of three (3) types   - wooden ploughs  - iron or inversion ploughs  - special purpose ploughs","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>5","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"The diagram below illustrates the use of a farm machinery.    A periodic maintenance activity carried out on the illustrated farm machinery is","images":["data:image/png;base64,"],"options":{"A":"checking the radiator water.","B":"checking of tyre pressure.","C":"changing of engine oil.","D":"cleaning after use"},"answer":"C","explanation":"Changing of engine oil. Changing engine oil is a crucial periodic maintenance activity for tractors and is essential for their proper functioning and longevity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>6","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PROSPECTS OF AGRICULTURAL MECHANIZATION","question":"A disadvantage of farm mechanization is","images":[],"options":{"A":"efficiency in farming.","B":"displacement of farm workers.","C":"reduction in health hazards.","D":"timeliness of farm operations."},"answer":"B","explanation":"Farm mechanization refers to the development and use of machines that can take over the tasks of human labour on farms. While it has many advantages such as increasing efficiency and reducing health hazards, a major disadvantage is that it can lead to the displacement of farm workers. This is because when machines take over the tasks that were previously done by humans, those humans are no longer needed, leading to job loss.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2019>7","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Calculate in hectares the area of a rectangular farmland with dimensions 50 by 25m.","images":[],"options":{"A":"125 ha","B":"12.5 ha","C":"1.25 ha","D":"0.125 ha"},"answer":"D","explanation":"It should be noted that:  1 hectare = 10,000m2 = 0.01m2 ----------------- (1)  1 ha = 0.01km2 ------------ (2)  Area of land given = 50m \u00d7 25m = 1250m2  1ha = 10,000m2  x = 1250m2  x=125010,000=0.125ha","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>8","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The practice of measuring and mapping out the size, position and boundary of a farmland is called farm","images":[],"options":{"A":"layout.","B":"business.","C":"surveying.","D":"tillage."},"answer":"C","explanation":"The practice of measuring and mapping out the size, position and boundary of a farmland is called Farm surveying.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>9","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Which of the following statements about land is not correct?","images":[],"options":{"A":"Its supply is limited","B":"It is used for agricultural production","C":"It is subject to depreciation","D":"It can be relocated"},"answer":"D","explanation":"Land cannot be relocated. It is a fixed resource. The other statements are correct: the supply of land is limited, it is used for agricultural production, and it can depreciate in value due to factors like soil erosion and degradation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>10","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"A socio-cultural factor affecting land availability is","images":[],"options":{"A":"soil type.","B":"religion.","C":"topography.","D":"mining."},"answer":"B","explanation":"Socio-cultural factors refer to societal and cultural factors that affect a community's behavior, preferences, and actions. Religion is a socio-cultural factor that can affect land availability as certain lands may be considered sacred or reserved for religious purposes, thus limiting their availability for agricultural use.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>11","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"A biotic factor affecting agricultural production is","images":[],"options":{"A":"rainfall","B":"predator","C":"humidity","D":"temperature"},"answer":"B","explanation":"Biotic factors are living or once-living organisms in the ecosystem which can affect agricultural production. Predators are biotic factors as they are living organisms that can affect the population of other organisms in the ecosystem, thus affecting agricultural production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>12","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following groups of organisms are parasitic plants?","images":[],"options":{"A":"Nematode, fungus and bacterium","B":"Striga, nematode and dodder","C":"Dodder, fungus and striga","D":"Mistletoe, fungus and bacterium"},"answer":"C","explanation":"Parasitic plants are plants that derive some or all of their nutritional requirements from another living plant. Dodder, fungus, and striga are all examples of parasitic plants. They harm their host plants by draining them of nutrients, which can affect agricultural production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>13","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"The type of rock formed from accumulation of materials transported by water is called","images":[],"options":{"A":"sedimentary rock.","B":"igneous rock.","C":"metamorphic rock.","D":"plutonic rock."},"answer":"A","explanation":"The type of rock formed from accumulation of materials transported by water is called Sedimentary rock.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>14","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A fresh garden soil sample weighed 25kg. When oven-dried, its weight reduced to 20kg. Calculate the percentage moisture content of the soil sample.","images":[],"options":{"A":"5.0%","B":"12.5%","C":"20.0%","D":"25.0%"},"answer":"C","explanation":"Parameters given  Mass of soil = 25kg  mass when overdried = 20kg  mass of moisture = 5kg  %ofpoisture=525\u00d7100=20%","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2019>15","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following mineral elements is essential for chlorophyll formation?","images":[],"options":{"A":"Calcium","B":"Boron","C":"Sodium","D":"Magnesium"},"answer":"D","explanation":"Magnesium is a crucial element for plants as it is a part of the chlorophyll molecule, which plants use for photosynthesis. Chlorophyll is what gives plants their green color. Without sufficient amounts of magnesium, plants cannot effectively carry out photosynthesis.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>16","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram below illustrates a soil profile. Study it.    The soil horizon that is not supportive of the growth of tree crops is","images":["data:image/png;base64,"],"options":{"A":"horizon A.","B":"horizon B.","C":"horizon C.","D":"horizon D."},"answer":"D","explanation":"The D-horizon where we have rocks is the least supportive of the growth of tree crops.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>17","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Liquid fertilizers and pesticides could be applied through","images":[],"options":{"A":"furrow irrigation.","B":"channel irrigation.","C":"sprinkler irrigation.","D":"flood irrigation."},"answer":"C","explanation":"Liquid fertilizers and pesticides can be applied through sprinkler irrigation. This method allows the substances to be evenly distributed across the field as they are mixed with the water that is sprayed out. Furrow, channel, and flood irrigation methods are not as effective for this purpose because they do not distribute the substances as evenly.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>18","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"In a crop rotation system, it is usually preferred that cassava comes last in the rotation because it","images":[],"options":{"A":"adds nitrogen to the soil.","B":"is a shallow feeder.","C":"is a deep rooted crop.","D":"is a perennial crop."},"answer":"C","explanation":"In a crop rotation system, it is usually preferred that cassava comes last in the rotation because it is a deep rooted crop.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>19","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The growing of only one crop on a piece of land from year to year is known as","images":[],"options":{"A":"mixed cropping.","B":"crop rotation.","C":"monoculture.","D":"shifting cultivation."},"answer":"C","explanation":"The growing of only one crop on a piece of land from year to year is known as monoculture. This practice can lead to soil nutrient depletion and increased vulnerability to pests and diseases. Mixed cropping involves growing two or more crops simultaneously on the same field, crop rotation involves growing different crops on the same land in sequenced seasons, and shifting cultivation involves moving from one piece of land to another after depleting the soil nutrients.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>20","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"In green manuring, crops are ploughed into the soil just before flowering in order to","images":[],"options":{"A":"control soil pathogens.","B":"enrich the soil with nutrients.","C":"control soil erosion.","D":"increase the soil temperature."},"answer":"B","explanation":"In green manuring crops are ploughed into the soil just before flowering in order to enrich the soil with nutrients.  N.B: Any crop which is buried in soil with the idea to increase soil quality, fertility and texture as well as structure is termed green manuring crop.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>21","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Corns, rhizomes and tubers are examples of","images":[],"options":{"A":"underground roots.","B":"underground stems.","C":"aerial stems.","D":"modified leaves."},"answer":"B","explanation":"Corns, rhizomes, and tubers are all examples of underground stems, not roots or leaves. They are specialized plant structures that store nutrients and help the plant survive in adverse conditions. They also allow the plant to reproduce asexually. An underground stem is a stem that grows horizontally under the soil and has nodes and internodes.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>22","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Which of the following statements is not a reason for budding? The resulting plants","images":[],"options":{"A":"can withstand adverse climatic conditions.","B":"flower and fruit early.","C":"are more disease resistant.","D":"develop broader leaves for photosynthesis."},"answer":"D","explanation":"The reasons for budding do not include the formation of plants with broader leaves for photosynthesis.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>23","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following statements are advantages of mulching? It   I. controls weeds.  II. conserves soil moisture.  III. increases soil temperature   IV. reduces soil pH.","images":[],"options":{"A":"I and II","B":"I and III","C":"II and IV","D":"III and IV"},"answer":"A","explanation":"\u21d2 Mulching prevents the water evaporation in the soil so it maintain soil moisture for a long time.  \u21d2 With the help of mulching it is easy to control weed because it suppresses weed.  \u21d2 It creates microclimate near plant root zone, so it help for healthy plant growth.  I and II","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>24","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"A planting material used in propagating plantain is the","images":[],"options":{"A":"crown.","B":"peeper.","C":"slip.","D":"leaf."},"answer":"C","explanation":"In the propagation of plantain, the planting material used is known as a 'slip'. A slip is a shoot that develops from the base of the plantain plant. It is detached and planted to produce a new plant. Therefore, the correct answer is 'slip'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>25","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"If maize seed is sown at a spacing of 100cm \u00d7 50cm, determine the expected maize plant population per hectare.","images":[],"options":{"A":"40,000","B":"20,000","C":"5,000","D":"2,000"},"answer":"C","explanation":"Land area = 100cm \u00d7 50cm  \u21d2 1.0m \u00d7 0.5m = 0.5m2    N.B: 1 ha = 10,000m2  For 1ha, we are going to have a total of  10,000 \u00d7 0.5 = 5,000 maize plants.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2019>26","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Protective functions of forests include the following except","images":[],"options":{"A":"soil conservation.","B":"serving as windbreak.","C":"purification of air.","D":"source of firewood."},"answer":"D","explanation":"The protective functions of forests include soil conservation, serving as windbreak, and purification of air. However, being a source of firewood is not a protective function of forests. Instead, it is a use or benefit derived from forests.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>27","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"FORESTRY : AGRO-FORESTRY PRACTICES IN WEST AFRICA","question":"The growing of both trees and arable crops on the same piece of land is","images":[],"options":{"A":"ley farming.","B":"mixed farming.","C":"forestry.","D":"taungya system."},"answer":"D","explanation":"The practice of growing both trees and arable crops on the same piece of land is known as the taungya system. In this system, farmers are allowed to grow crops between the rows of planted trees. This is not to be confused with ley farming, mixed farming, or forestry, which are different agricultural practices.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>28","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Sexual propagation of ornamental plants involves the use of","images":[],"options":{"A":"stems.","B":"seeds.","C":"suckers.","D":"rhizomes."},"answer":"B","explanation":"Sexual propagation of ornamental plants involves the use of seeds. This is because sexual propagation involves the fusion of male and female gametes to produce a new plant. The seeds contain these gametes. Stems, suckers, and rhizomes are used in asexual propagation, where a new plant is produced without the fusion of gametes.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>29","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The vector of leaf curl disease of cotton is","images":[],"options":{"A":"grasshopper.","B":"termites.","C":"thrips.","D":"white fly."},"answer":"D","explanation":"Leaf curl disease of cotton is transmitted by whiteflies. Whiteflies are tiny, sap-sucking insects that are often found in thick crowds on the undersides of leaves. When infected whiteflies feed on plant sap, they leave behind leaf curl disease.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>30","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"A major storage pest of cereals in West Africa is","images":[],"options":{"A":"stem borer.","B":"weevil.","C":"bird.","D":"army worm."},"answer":"B","explanation":"Weevils are a major storage pest of cereals in West Africa. They are small beetles that lay their eggs in grain kernels and the larvae feed on the grain from the inside. This can cause significant damage to stored cereals.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>31","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Biological control of insect-pests of crops is carried out through","images":[],"options":{"A":"crop rotation.","B":"use of predators.","C":"use of pesticides.","D":"farm sanitation."},"answer":"B","explanation":"Biological control of insect-pests of crops is carried out through use of predators.  It should be noted that biological control of pests involve the use of the natural enemy of the pest.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>32","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"During the production of palm oil, the oil palm fruits are boiled in order to","images":[],"options":{"A":"harden the kernel.","B":"prevent high level of oil rancidity.","C":"extract oil from the palm fruit.","D":"separate mesocarp from endocarp."},"answer":"D","explanation":"During the production of palm oil, the oil palm fruits are boiled primarily to separate the mesocarp (the fleshy part of the fruit) from the endocarp (the hard shell that encloses the seed or kernel). This process makes it easier to extract the oil from the fruit. The boiling process does not harden the kernel, prevent oil rancidity, or directly extract oil from the palm fruit.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>33","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Which of the following breeds of cattle is exotic?","images":[],"options":{"A":"Sokoto Gudali","B":"Ndama","C":"Friesian","D":"Muturu"},"answer":"C","explanation":"Exotic breeds of cattle include:  - Jersey  - Holstein Friesia  - Brown Swiss  - Red Dane  - Ayrshire  - Guernsey","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>34","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Study the diagram below and this question.      The diagram represents the digestive system of a","images":["data:image/png;base64,"],"options":{"A":"buck.","B":"cock.","C":"bull.","D":"sow."},"answer":"B","explanation":"The diagram represents the digestive system of a cock.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>35","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Study the diagram below and this question.    The main function of the part labelled I is","images":["data:image/png;base64,"],"options":{"A":"temporary storage of food.","B":"production of digestive enzymes.","C":"crushing of food particles.","D":"transportation of food nutrients."},"answer":"A","explanation":"The part labelled I is the \"crop\".  The main function of the crop is used to temporarily store food.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>36","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Which of the following hormones is responsible for oestrus in farm animals?","images":[],"options":{"A":"Oxytocin","B":"Oestrogen","C":"Prolactin","D":"Progesterone"},"answer":"B","explanation":"Oestrogen is the hormone responsible for oestrus (also known as 'heat') in farm animals. Oestrus is the period of sexual receptivity in female mammals, during which they are ready to mate. Oestrogen triggers the physical and behavioral changes associated with oestrus. Oxytocin, prolactin, and progesterone are also hormones that play roles in the reproductive processes of animals, but they are not directly responsible for oestrus.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>37","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"In animal production, immature spermatozoa are stored in the","images":[],"options":{"A":"urethra.","B":"scrotum.","C":"epididymis.","D":"prostate gland."},"answer":"C","explanation":"In animal production, immature spermatozoa are stored in the epididymis. The epididymis is a long, coiled tube that rests on the backside of each testicle. It functions in the transport and storage of the sperm cells that are produced in the testes. It also is the job of the epididymis to bring the sperm to maturity, since the sperm that emerge from the testes are immature and incapable of fertilization.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>38","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"The least important factor for successful incubation of eggs is","images":[],"options":{"A":"light.","B":"temperature.","C":"ventilation.","D":"humidity."},"answer":"A","explanation":"The least important factor for successful incubation of eggs is light. The most important factors for successful incubation are temperature, humidity, and ventilation. These factors ensure that the embryo develops properly. Light is not as crucial as these factors. While light can be used to monitor the development of the egg (a process called candling), it is not a requirement for the egg to develop.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>39","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A wallow should be provided in the pen of pigs in order to","images":[],"options":{"A":"reduce the feed intake of pigs.","B":"increase the water intake of pigs.","C":"enable the pigs to swim.","D":"cool the temperature of pigs."},"answer":"D","explanation":"A wallow should be provided in the pen of pigs in order to cool their temeprature because they have little ability to sweat.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>40","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"The data for feed consumption and weight gain of four farm animals labelled P, Q, R and S are shown below. Use the data to answer this question  P: 50kg feed consumed and 20kg weight gained    Q: 90kg feed consumed and 30kg weight gained    R: 100kg feed consumed and 25kg weight gained    S: 150kg feed consumed and 30kg weight gained    Which of the animals is the most efficient feed converter?","images":[],"options":{"A":"P","B":"Q","C":"R","D":"S"},"answer":"A","explanation":"In P, the feed conversion = 40%  In Q, the feed conversion = 33.3%  In R, the feed conversion = 25%  In S, the feed conversion = 20%","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2019>41","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"The data for feed consumption and weight gain of four farm animals labelled P, Q, R and S are shown below. Use the data to answer this question  P: 50kg feed consumed and 20kg weight gained    Q: 90kg feed consumed and 30kg weight gained    R: 100kg feed consumed and 25kg weight gained    S: 150kg feed consumed and 30kg weight gained  The feed conversion efficiency of the poorest weight gainer is","images":[],"options":{"A":"0.40","B":"0.33","C":"0.25","D":"0.20"},"answer":"D","explanation":"As explained in the previous question, the feed conversion efficiency is calculated by dividing the weight gained by the amount of feed consumed. The animal with the lowest feed conversion efficiency is the poorest weight gainer. Therefore, S with a feed conversion efficiency of 0.2 is the poorest weight gainer.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2019>42","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Bone meal is usually included in the diet of livestock to supply","images":[],"options":{"A":"calcium and phosphorus.","B":"calcium and iodine.","C":"phosphorus and iron.","D":"magnesium and sodium."},"answer":"A","explanation":"Bone meal is a mixture of finely and coarsely ground animal bones and slaughter-house waste products. It is used as an organic fertilizer for plants and as a nutritional supplement for animals. As a slow-release fertilizer, bone meal is primarily used as a source of phosphorus and protein. But it also contains a high amount of calcium, but no iodine, iron, or sodium. Therefore, the correct answer is 'calcium and phosphorus.'","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>43","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Which of the following statements about inbreeding in farm animals is/are false?  I. Inbred animals reach market weight early  II. Inbred animals have reduced vigour  III. Inbreding increases the occurrence of undesirable traits.","images":[],"options":{"A":"I only","B":"II only","C":"I and II only","D":"I and III only"},"answer":"D","explanation":"Inbreeding in farm animals is the mating of animals that are closely related. This can lead to several negative effects such as reduced vigour and increased occurrence of undesirable traits. However, it does not make animals reach market weight early. Therefore, statements I and III are false.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>44","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following parasites may be found in the gut of livestock?","images":[],"options":{"A":"Tick","B":"Flea","C":"Round worm","D":"Louse"},"answer":"C","explanation":"Parasites that live in the gut of livestock are typically internal parasites, also known as endoparasites. These include roundworms, tapeworms, and flukes. Ticks, fleas, and lice are external parasites, or ectoparasites, that live on the outside of the animal's body.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>45","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Vegetative growth in fish pond","images":[],"options":{"A":"makes fish movement easy.","B":"regulates water acidity.","C":"increases pond water turbidity.","D":"moderates pond temperature."},"answer":"C","explanation":"Vegetative growth in a fish pond refers to the growth of plants and algae. This can increase the turbidity, or cloudiness, of the water, which can make it difficult for fish to see and can reduce the amount of light that penetrates the water. It does not make fish movement easy, regulate water acidity, or moderate pond temperature.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>46","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Which of the following factors of agricultural production is abundant in rural areas?","images":[],"options":{"A":"Enterprise","B":"Land","C":"Labour","D":"Capital"},"answer":"B","explanation":"In rural areas, land is the most abundant factor of agricultural production. This is because rural areas are typically less developed and less densely populated than urban areas, allowing for more space for agricultural activities. The other options, Enterprise, Labour, and Capital, are not as abundant in rural areas. Enterprise refers to the organization of the other three factors of production and is not a physical resource. Labour, while present in rural areas, is not as abundant as land. Capital, which refers to man-made resources used in production, is typically more abundant in urban areas where there is more development.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2019>47","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Study the graph illustrated below and answer this question.      The graph best","images":["data:image/png;base64,"],"options":{"A":"shows an increase in the supply of rice.","B":"describes a shift in the demand for rice.","C":"describes the equilibrium price for rice.","D":"shows that the demand for rice exceeds supply."},"answer":"C","explanation":"The graph best describes the equilibrium price for rice.  The equilibrium price is the price at which the quantity demanded equals the quantity supplied. Graphically, it is the point at which two curves intersect.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>48","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Study the graph illustrated below and answer this question.    What is the change in quantity of rice demanded when the price increases from \u20a61.00 to \u20a65.00?","images":["data:image/png;base64,"],"options":{"A":"8kg","B":"6kg","C":"4kg","D":"2kg"},"answer":"B","explanation":"When the price increase from \u20a61.00 to \u20a65.00, the change in quantity of rice demanded = 8kg - 2kg = 6kg.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>49","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Study the graph illustrated below and answer this question.    Determine the equilibrium price of rice.","images":["data:image/png;base64,"],"options":{"A":"\u20a61.00","B":"\u20a62.00","C":"\u20a63.00","D":"\u20a64.00"},"answer":"B","explanation":"The equilibrium price of rice is \u20a62.00. The equilibrium price in demand and supply refers to the price at which the quantity of a product demanded by consumers equals the quantity supplied by producers in the agricultural market.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2019>50","subject":"Agricultural Science","year":"2019","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"A major characteristic of mass teaching method of agricultural extension is that","images":[],"options":{"A":"information can be directed to a large number of people at different locations.","B":"it demonstrates how to carry out new techniques to farmers in the same locality.","C":"feedback is readily available to extension officers.","D":"it summarizes and analyses what had been done in previous learning situations."},"answer":"A","explanation":"The mass teaching method of agricultural extension is characterized by the ability to disseminate information to a large number of people at different locations. This method is often used in situations where individual or small group instruction is not feasible or cost-effective. The other options do not accurately describe the characteristics of the mass teaching method. While feedback may be available to extension officers, it is not a defining characteristic of the mass teaching method. Similarly, demonstrating new techniques and summarizing previous learning situations are not specific to the mass teaching method.","marks":"1","difficulty":"2"}];